import{_ as e,o as t,c as s,a2 as l}from"./chunks/framework.DRBHoC6Q.js";const b=JSON.parse('{"title":"回款风险 Top 3 模块 MVP 技术方案初稿","description":"","frontmatter":{},"headers":[],"relativePath":"modules/receivable-risk.md","filePath":"modules/receivable-risk.md","lastUpdated":1783323851000}'),i={name:"modules/receivable-risk.md"};function n(p,a,d,r,h,o){return t(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="回款风险-top-3-模块-mvp-技术方案初稿" tabindex="-1">回款风险 Top 3 模块 MVP 技术方案初稿 <a class="header-anchor" href="#回款风险-top-3-模块-mvp-技术方案初稿" aria-label="Permalink to &quot;回款风险 Top 3 模块 MVP 技术方案初稿&quot;">​</a></h1><p>文档版本：V0.1<br> 状态：讨论稿，风险阈值待产品与财务确认<br> 目标读者：产品、财务、后端开发和测试人员</p><h2 id="_1-模块目标" tabindex="-1">1. 模块目标 <a class="header-anchor" href="#_1-模块目标" aria-label="Permalink to &quot;1. 模块目标&quot;">​</a></h2><p>本模块识别当前最需要关注的应收款，回答以下问题：</p><ul><li>哪些应收尚未全部到账；</li><li>哪些应收已经逾期或即将到期；</li><li>当前未回金额是多少；</li><li>应优先关注哪三笔应收；</li><li>每笔风险应收由谁负责。</li></ul><p>风险等级和排序由确定性规则计算。AI 不参与金额、到期状态、风险等级或 Top 3 排序，只能解释已经计算出的结果。</p><h2 id="_2-mvp-范围" tabindex="-1">2. MVP 范围 <a class="header-anchor" href="#_2-mvp-范围" aria-label="Permalink to &quot;2. MVP 范围&quot;">​</a></h2><h3 id="_2-1-本期实现" tabindex="-1">2.1 本期实现 <a class="header-anchor" href="#_2-1-本期实现" aria-label="Permalink to &quot;2.1 本期实现&quot;">​</a></h3><ul><li>计算每笔应收的累计实际回款和未回金额；</li><li>计算逾期、今日到期、临期和正常状态；</li><li>按统一规则生成红、黄、绿风险等级；</li><li>从红色和黄色候选中选出回款风险 Top 3；</li><li>返回客户、金额、负责人、到期状态和最近跟进信息；</li><li>支持从结果追溯到应收款和实际回款记录。</li></ul><h3 id="_2-2-本期不实现" tabindex="-1">2.2 本期不实现 <a class="header-anchor" href="#_2-2-本期不实现" aria-label="Permalink to &quot;2.2 本期不实现&quot;">​</a></h3><ul><li>使用 AI 猜测客户是否会付款；</li><li>根据客户历史行为训练违约概率模型；</li><li>节假日或工作日历计算；</li><li>客户信用评分和外部征信；</li><li>自动发送催收消息或执行资金操作。</li></ul><h2 id="_3-数据来源" tabindex="-1">3. 数据来源 <a class="header-anchor" href="#_3-数据来源" aria-label="Permalink to &quot;3. 数据来源&quot;">​</a></h2><h3 id="_3-1-主表-应收款" tabindex="-1">3.1 主表：应收款 <a class="header-anchor" href="#_3-1-主表-应收款" aria-label="Permalink to &quot;3.1 主表：应收款&quot;">​</a></h3><p>回款风险以应收款为主表。主要使用：</p><ul><li>应收编号；</li><li>客户；</li><li>应收金额；</li><li>约定到账日期；</li><li>当前预计到账日期；</li><li>责任人；</li><li>业务状态。</li></ul><h3 id="_3-2-关联表-实际回款" tabindex="-1">3.2 关联表：实际回款 <a class="header-anchor" href="#_3-2-关联表-实际回款" aria-label="Permalink to &quot;3.2 关联表：实际回款&quot;">​</a></h3><p>实际回款用于扣除已经到账的金额。一笔应收可以关联多笔实际回款。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一笔应收款 1 → N 笔实际回款</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-3-辅助数据-回款跟进记录" tabindex="-1">3.3 辅助数据：回款跟进记录 <a class="header-anchor" href="#_3-3-辅助数据-回款跟进记录" aria-label="Permalink to &quot;3.3 辅助数据：回款跟进记录&quot;">​</a></h3><p>如果需要展示“今日待反馈”“跟进中”或最近跟进内容，可关联回款跟进记录，读取最近一次跟进时间、内容和下次跟进日期。</p><p>跟进记录只影响页面状态和任务处理，不直接改变应收金额、未回金额和风险等级。</p><h2 id="_4-计算基准" tabindex="-1">4. 计算基准 <a class="header-anchor" href="#_4-计算基准" aria-label="Permalink to &quot;4. 计算基准&quot;">​</a></h2><p>每次计算必须指定统计日期 <code>asOfDate</code>，本文记为 <code>D</code>。</p><p>所有应收和实际回款必须来自同一个已发布数据批次。未发布、已作废或校验失败的数据不得进入正式计算。</p><h2 id="_5-未回金额计算" tabindex="-1">5. 未回金额计算 <a class="header-anchor" href="#_5-未回金额计算" aria-label="Permalink to &quot;5. 未回金额计算&quot;">​</a></h2><p>对每笔有效应收：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>累计实际回款</span></span>
<span class="line"><span>= Σ 关联到该应收的有效实际回款金额</span></span>
<span class="line"><span></span></span>
<span class="line"><span>未回金额</span></span>
<span class="line"><span>= max(应收金额 - 累计实际回款, 0)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>处理规则：</p><ul><li>未回金额等于 0，表示已经全部回款，不进入风险候选；</li><li>部分回款后仍有余额，继续按照剩余未回金额判断风险；</li><li>累计回款超过应收金额时，未回金额按 0 处理，并返回数据异常警告；</li><li>业务状态为 <code>cancelled</code> 或数据状态无效的应收不参与计算。</li></ul><h2 id="_6-到期状态计算" tabindex="-1">6. 到期状态计算 <a class="header-anchor" href="#_6-到期状态计算" aria-label="Permalink to &quot;6. 到期状态计算&quot;">​</a></h2><p>逾期和临期以约定到账日期 <code>agreed_due_date</code> 为判断依据，不使用预计到账日期替代合同约定。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>距到期天数 = 约定到账日期 - D</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>MVP 使用自然日：</p><table tabindex="0"><thead><tr><th>条件</th><th>到期状态</th><th>页面建议文案</th></tr></thead><tbody><tr><td>距到期天数 &lt; 0</td><td>已逾期</td><td>逾期 N 天</td></tr><tr><td>距到期天数 = 0</td><td>今日到期</td><td>今日到期</td></tr><tr><td>距到期天数 = 1</td><td>临期</td><td>明日到期</td></tr><tr><td>距到期天数 = 2</td><td>临期</td><td>还有 2 天到期</td></tr><tr><td>距到期天数 &gt; 2</td><td>正常</td><td>距到期 N 天</td></tr></tbody></table><p>逾期天数定义：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>如果未回金额 = 0：逾期天数 = 0</span></span>
<span class="line"><span>否则：逾期天数 = max(D - 约定到账日期, 0)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="_7-风险等级" tabindex="-1">7. 风险等级 <a class="header-anchor" href="#_7-风险等级" aria-label="Permalink to &quot;7. 风险等级&quot;">​</a></h2><p>MVP 按最高风险条件命中：</p><h3 id="_7-1-红色风险" tabindex="-1">7.1 红色风险 <a class="header-anchor" href="#_7-1-红色风险" aria-label="Permalink to &quot;7.1 红色风险&quot;">​</a></h3><p>满足任一条件：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>逾期天数 &gt;= 30 天</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>已经逾期且未回金额 &gt;= 1,000,000 元</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="_7-2-黄色风险" tabindex="-1">7.2 黄色风险 <a class="header-anchor" href="#_7-2-黄色风险" aria-label="Permalink to &quot;7.2 黄色风险&quot;">​</a></h3><p>未触发红色风险，并满足任一条件：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>逾期天数为 1～29 天</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>距到期天数为 0～2 天</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>黄色风险因此同时包含轻度逾期、今日到期和未来两天内临期的应收。</p><h3 id="_7-3-绿色状态" tabindex="-1">7.3 绿色状态 <a class="header-anchor" href="#_7-3-绿色状态" aria-label="Permalink to &quot;7.3 绿色状态&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>未回金额 &gt; 0</span></span>
<span class="line"><span>且</span></span>
<span class="line"><span>距到期天数 &gt; 2 天</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>绿色代表当前未临期，不代表应收已经到账。已经全部回款的应收直接退出当前风险候选，不使用绿色风险继续展示。</p><h2 id="_8-top-3-候选和排序" tabindex="-1">8. Top 3 候选和排序 <a class="header-anchor" href="#_8-top-3-候选和排序" aria-label="Permalink to &quot;8. Top 3 候选和排序&quot;">​</a></h2><h3 id="_8-1-候选范围" tabindex="-1">8.1 候选范围 <a class="header-anchor" href="#_8-1-候选范围" aria-label="Permalink to &quot;8.1 候选范围&quot;">​</a></h3><p>Top 3 只从红色和黄色风险中选择：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>候选应收</span></span>
<span class="line"><span>= 有效应收</span></span>
<span class="line"><span>且未回金额 &gt; 0</span></span>
<span class="line"><span>且风险等级属于 red 或 yellow</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果候选不足三笔，则按实际数量展示，不使用模拟数据补足。</p><h3 id="_8-2-排序规则" tabindex="-1">8.2 排序规则 <a class="header-anchor" href="#_8-2-排序规则" aria-label="Permalink to &quot;8.2 排序规则&quot;">​</a></h3><p>排序键依次为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 风险等级：红色优先于黄色</span></span>
<span class="line"><span>2. 到期紧急程度：逾期 &gt; 今日到期 &gt; 明日到期 &gt; 还有 2 天到期</span></span>
<span class="line"><span>3. 同类逾期：逾期天数更多的优先</span></span>
<span class="line"><span>4. 条件仍相同：未回金额更大的优先</span></span>
<span class="line"><span>5. 条件仍相同：应收编号升序，保证结果稳定</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>取排序后的前三笔作为页面 Top 3。</p><h2 id="_9-页面展示字段" tabindex="-1">9. 页面展示字段 <a class="header-anchor" href="#_9-页面展示字段" aria-label="Permalink to &quot;9. 页面展示字段&quot;">​</a></h2><p>每条 Top 3 记录至少展示：</p><ul><li>客户名称；</li><li>应收编号；</li><li>原始应收金额；</li><li>已回金额；</li><li>未回金额；</li><li>约定到账日期；</li><li>逾期或临期文案；</li><li>风险等级；</li><li>责任人；</li><li>最近跟进时间和状态（存在跟进数据时）。</li></ul><p>页面中的金额、日期、负责人和风险等级必须可以追溯到参与计算的业务记录和规则版本。</p><h2 id="_10-计算示例" tabindex="-1">10. 计算示例 <a class="header-anchor" href="#_10-计算示例" aria-label="Permalink to &quot;10. 计算示例&quot;">​</a></h2><p>假设统计日期为 7 月 5 日：</p><table tabindex="0"><thead><tr><th>应收</th><th style="text-align:right;">应收金额</th><th style="text-align:right;">已回金额</th><th style="text-align:right;">未回金额</th><th>约定到账日</th><th>结果</th></tr></thead><tbody><tr><td>A</td><td style="text-align:right;">300 万</td><td style="text-align:right;">0</td><td style="text-align:right;">300 万</td><td>7 月 4 日</td><td>逾期 1 天，因逾期且金额超过 100 万，红色</td></tr><tr><td>B</td><td style="text-align:right;">200 万</td><td style="text-align:right;">50 万</td><td style="text-align:right;">150 万</td><td>7 月 6 日</td><td>明日到期，黄色</td></tr><tr><td>C</td><td style="text-align:right;">160 万</td><td style="text-align:right;">0</td><td style="text-align:right;">160 万</td><td>7 月 7 日</td><td>还有 2 天到期，黄色</td></tr><tr><td>D</td><td style="text-align:right;">80 万</td><td style="text-align:right;">80 万</td><td style="text-align:right;">0</td><td>6 月 30 日</td><td>已全部回款，不进入候选</td></tr><tr><td>E</td><td style="text-align:right;">90 万</td><td style="text-align:right;">0</td><td style="text-align:right;">90 万</td><td>7 月 20 日</td><td>未临期，绿色，不进入 Top 3</td></tr></tbody></table><p>最终 Top 3 为 A、B、C。</p><h2 id="_11-输出结果最低要求" tabindex="-1">11. 输出结果最低要求 <a class="header-anchor" href="#_11-输出结果最低要求" aria-label="Permalink to &quot;11. 输出结果最低要求&quot;">​</a></h2><p>结果至少包含：</p><ul><li>统计日期、数据批次和规则版本；</li><li>风险候选总数及红色、黄色数量；</li><li>排序后的 Top 3；</li><li>每笔应收的原始金额、累计回款、未回金额和到期状态；</li><li>风险等级及命中的规则；</li><li>参与计算的应收和实际回款来源标识；</li><li>超额回款、日期缺失或责任人缺失等数据警告。</li></ul><p>金额必须使用十进制定点计算，禁止使用二进制浮点数直接计算财务金额。</p><h2 id="_12-mvp-验收标准" tabindex="-1">12. MVP 验收标准 <a class="header-anchor" href="#_12-mvp-验收标准" aria-label="Permalink to &quot;12. MVP 验收标准&quot;">​</a></h2><ul><li>已全部回款的应收不进入风险候选；</li><li>部分回款按照剩余未回金额判断风险；</li><li>今日到期及未来两天内到期的应收进入黄色候选；</li><li>红色始终排在黄色之前；</li><li>相同输入、统计日期和规则版本产生完全一致的 Top 3；</li><li>候选不足三笔时不使用模拟数据补足；</li><li>每个结果可以追溯到应收款和实际回款记录。</li></ul><h2 id="_13-待确认口径" tabindex="-1">13. 待确认口径 <a class="header-anchor" href="#_13-待确认口径" aria-label="Permalink to &quot;13. 待确认口径&quot;">​</a></h2><ol><li>临期长期采用 2 个自然日，还是改为工作日；</li><li>红色大额阈值是否采用 100 万元；</li><li>红色逾期阈值是否采用 30 天；</li><li>客户等级或业务线是否参与风险排序；</li><li>已承诺新到账日期是否只展示，还是影响风险等级；</li><li>最近跟进超时是否影响回款风险，还是只影响风险任务等级。</li></ol>`,73)])])}const u=e(i,[["render",n]]);export{b as __pageData,u as default};
